   333	// shellQuoteArgs returns args concatenated as a single POSIX shell command,
   334	// with each argument single-quoted (any single quotes inside an arg are
   335	// escaped via the standard '\'' trick).
   336	func shellQuoteArgs(args []string) string {
   337		parts := make([]string, len(args))
