   344	func shellQuote(s string) string {
   345		if s == "" {
   346			return "''"
   347		}
   348		// Fast path for "safe" args: alphanumerics and a few specific chars.
   349		safe := true
   350		for _, r := range s {
   351			switch {
   352			case 'a' <= r && r <= 'z',
   353				'A' <= r && r <= 'Z',
   354				'0' <= r && r <= '9',
   355				r == '/' || r == '.' || r == '_' || r == '-' || r == '+' || r == '=' || r == ':' || r == ',':
   356			default:
   357				safe = false
   358			}
   359			if !safe {
   360				break
   361			}
   362		}
   363		if safe {
   364			return s
   365		}
   366		return "'" + strings.ReplaceAll(s, "'", `'\''`) + "'"
   367	}
