   369	// kdlQuote returns s wrapped in KDL-safe double quotes, escaping any
   370	// embedded double quotes and backslashes.
   371	func kdlQuote(s string) string {
   372		var b bytes.Buffer
   373		b.WriteByte('"')
   374		for _, r := range s {
   375			switch r {
   376			case '\\':
   377				b.WriteString(`\\`)
   378			case '"':
   379				b.WriteString(`\"`)
   380			case '\n':
   381				b.WriteString(`\n`)
   382			case '\r':
   383				b.WriteString(`\r`)
   384			case '\t':
   385				b.WriteString(`\t`)
   386			default:
   387				b.WriteRune(r)
   388			}
   389		}
   390		b.WriteByte('"')
   391		return b.String()
   392	}
