   436	func newRingCapture(limit int) *ringCapture {
   437		if limit <= 0 {
   438			limit = 4 * 1024
   439		}
   440		return &ringCapture{limit: limit, buf: make([]byte, 0, limit)}
   441	}
   442	
   443	func (r *ringCapture) Write(p []byte) (int, error) {
   444		for _, b := range p {
   445			if !r.full {
   446				r.buf = append(r.buf, b)
   447				if len(r.buf) == r.limit {
   448					r.full = true
   449					r.pos = 0
   450				}
   451			} else {
   452				r.buf[r.pos] = b
   453				r.pos++
   454				if r.pos == r.limit {
   455					r.pos = 0
   456				}
   457			}
   458		}
   459		return len(p), nil
   460	}
