+  const paths = expanded
+    ? directoryPaths
+    : getReversedFileTreeDirectoryPaths(directoryPaths);
+  for (const path of paths) {
+    const directory = getFileTreeDirectoryHandle(model, path);
+    if (!directory || directory.isExpanded() === expanded) {
+      continue;
+    }
