+
+function getFileTreeDirectoryHandle(
+  model: FileTreeModel,
+  path: string
+): FileTreeDirectoryHandle | null {
+  const item = model.getItem(path);
+  if (!isFileTreeDirectoryHandle(item)) {
+    return null;
+  }
