+  const reversedPaths: string[] = [];
+  for (let index = paths.length - 1; index >= 0; index -= 1) {
+    const path = paths[index];
+    if (path) {
+      reversedPaths.push(path);
+    }
+  }
+
+  return reversedPaths;
+}
